arguments.argument:
if global.gamePaused=false
{
  if progCheck=1 //Move direction on a set time
  {
    if soundUse=1 {playSound(global.snd_Slam,0,1,1)}
    soundUse=0
    xVel=xMove
    yVel=yMove
    moveTime+=1
    if moveTime>=moveMax
    {
      xVel=0; yVel=0
      progCheck=2
    }
  }
  scrPlatformCrush()
}
